test_sentences = [
    "这是一个非常复杂的神经翻译系统。",
    "我们需要更多的算力来训练这个模型。",
    "人工智能正在改变我们的生活方式。"
]

for s in test_sentences:
    print(f"原文: {s}")
    print(f"翻译: {translate(s)}")
    print("-" * 30)
